<template>
  <el-main>
    <el-card v-for="item in cardArr" :key="item.id" class="card animate__animated animate__flipInX">
      <div slot="header" style="text-align: left;">
        <span v-html="item.title"></span>
      </div>
      <div class="flex">
        <img :src="require(`@/assets/images/${item.pic}`)" alt="novel" height="100" width="100">
        <div class="context" v-html="item.text"></div>
      </div>
    </el-card>
  </el-main>
</template>

<script>

export default {
  name: 'Eye',
  data: () => ({
    cardArr: [
      {
        id: 1,
        title: '动画效果',
        pic: 'nv.jpeg',
        text: '<span class="tag">appear</span>属性可以使动画在初始化渲染时就加载<br>自定义class时 transform会覆盖掉elementUI的样式 导致动画过渡失效'
      },
      {
        id: 2,
        title: 'v-html&ensp;渲染问题',
        pic: 'nv3.jpeg',
        text: '<span class="tag">v-html</span>渲染内容时，元素的样式应该写在不带有<span class="tag">scoped</span>属性的<span class="tag">style</span>标签中，否则元素的样式将不会被渲染'
      },
      {
        id: 3,
        title: '鼠标悬浮样式',
        pic: 'nv4.jpeg',
        text: '鼠标悬浮卡片时，若想悬浮样式只影响指定元素，只需要在:hover后加上指定的元素即可<br>例：<span class="tag">:hover > img</span>'
      },
      {
        id: 4,
        title: '文字溢出处理',
        pic: 'nv12.jpeg',
        text: '当盒子里的文字过多时，想让超出的文字显示为...怎么办？先给盒子一个固定高度并且溢出部分隐藏，然后给个行高（高度除以显示的行数），然后设置盒子的<span class="tag">display</span>属性为<span class="tag">-webkit-box</span>'
      },
      {
        id: 5,
        title: 'el-backtop&ensp;渲染问题',
        pic: 'nv19.jpeg',
        text: '使用<span class="tag">el-backtop</span>时，如果不显示，可以将<span class="tag">el-backtop</span>标签放在外层容器的最底部或将<span class="tag">target</span>属性移除，如果想要自定义，可以在<span class="tag">el-backtop</span>标签内嵌套一个<span class="tag">div</span>'
      }
    ]
  }),
  mounted() {
    this.placeholder()
    this.$scroll()
  },
  methods: {
    // 占位处理
    placeholder() {
      if (!!this.cardArr) {
        let mark = this.cardArr.length % 2;
        if (mark > 0) {
          for (let i = 0; i < mark; i++) {
            let span = document.createElement('span')
            span.style.width = '500px'
            document.querySelector('.el-main').appendChild(span)
          }
        }
      }
    }
  }
}
</script>

<style scoped>

/* el-card */
.card {
  position: relative;
  width: 500px;
  height: 205px;
  margin-top: 10px;
  /* 卡片背景虚化 */
  background: #ffffff24;
  transition: background-color 1s;
}

/* 悬浮卡片背景实化 */
.card:hover {
  background: #ffffff;
}

/* 卡片内容 */
.context {
  text-align: left;
  width: calc(100% - 100px);
  height: 105px;
  line-height: 35px;
  font-size: 14px;
  overflow: hidden;
  display: -webkit-box;
  -webkit-line-clamp: 3;
  -webkit-box-orient: vertical;
  user-select: none;
}

/* 卡片图 */
div[class=flex] img {
  border-radius: 8px;
  margin-right: 8px;
  object-fit: cover;
  transition: .5s;
}

div[class=flex]:hover > img {
  transform: scale(1.1);
}
</style>
